head.script:
//-------------------------------------------------------------------------
// 전역변수 선언
//-------------------------------------------------------------------------
scwin.strCurrDate = WebSquare.date.getCurrentServerDate(); // 서버기준 현재날짜
scwin.strStartDate = scwin.strCurrDate.substring(0, 6) + "01"; // 조회 시작일자

scwin.params  = "";
scwin.flag  = "";
scwin.selPchLodeptCd  = "";
scwin.qryConDt  = "";
scwin.qryConLastDt  = "";
scwin.acctCd  = "";
scwin.acctNm  = "";
scwin.strcopCoClntNo  = "";
scwin.strcopCoClntNm  = "";
scwin.strlobranCd  = "";
scwin.strlobranNm  = "";


scwin.ed_acctCd = "";


// 계정별 확정 미확정 조회에서 넘어올때 DataMap 받아옴
scwin.ds_parent = "";
scwin.olddata = "";
scwin.eventCnt = 0;

//-------------------------------------------------------------------------
// 화면 로딩시
//-------------------------------------------------------------------------
scwin.onpageload = function() {

// 파라미터 정의
scwin.params = $c.data.getParameter(); // 호출시 파라미터 전체(Json으로 반아옴)

scwin.flag = scwin.params.flag == null ? "" :scwin.params.flag;	
scwin.selPchLodeptCd = scwin.params.selPchLodeptCd == null ? "" :scwin.params.selPchLodeptCd;
scwin.qryConDt = scwin.params.qryConDt == null ? "" :scwin.params.qryConDt;
scwin.qryConLastDt = scwin.params.qryConLastDt == null ? "" :scwin.params.qryConLastDt;
scwin.acctCd = scwin.params.acctCd == null ? "" :scwin.params.acctCd;
scwin.acctNm = scwin.params.acctNm == null ? "" :scwin.params.acctNm;
scwin.strcopCoClntNo = scwin.params.copCoClntNo == null ? "" :scwin.params.copCoClntNo;
scwin.strcopCoClntNm = scwin.params.copCoClntNm == null ? "" :scwin.params.copCoClntNm;
scwin.strlobranCd = scwin.params.strlobranCd == null ? "" :scwin.params.strlobranCd;
scwin.strlobranNm = scwin.params.strlobranNm == null ? "" :scwin.params.strlobranNm;


scwin.ds_parent = scwin.params.dma_queryConditionDTO;





    //공통코드데이터 호출   
    const codeOptions = [
        { grpCd: "SD187", compID: "acb_retStd" }, // 셀렉트
        { grpCd: "LO112", compID: "acb_clntCls" }, // 셀렉트
        { grpCd: "SD113", compID: "acb_odrKndCd" }, // 셀렉트
        { grpCd: "FS500", compID: "acb_dcsnClsCd" }, // 셀렉트
        // { grpCd: "LogisticsPurchaseEvidenceEBC", compID: "acb_odrKndCd" }, // 셀렉트
    ];
    $c.data.setCommonCode(codeOptions);

    const param= [
        {
            method: "getLuxeComboData",
            param1: "LogisticsPurchaseEvidenceEBC",
            param2: "retriveSelpchItemCdList",
            compID: "acb_selpchItemCd"
        }
    ];
    $c.data.setGauceUtil(param);

    // scwin.f_SetDefaultData()

    if(scwin.flag != "") {
        // 계정별에서 넘어오는 DataMap 복사해서 사용
        dma_parent.setArray({"columnInfo" : dataColumn 
                                , "data" : scwin.ds_parent});
        scwin.f_WholeRetrieve(dma_parent);
    }



};


//-------------------------------------------------------------------------
// Default Data Setting
//-------------------------------------------------------------------------
scwin.f_SetDefaultData = function() {
    udc_calendar.setStyle("display", "block");  // 오더일자, 실적일자
    udc_odrNo.setStyle("display", "none");  // 오더번호
    udc_BL.setStyle("display", "none"); // BL검색
    div_qryConKnd4.setStyle("display", "block");  // 품명
    div_qryConKnd5.setStyle("display", "none");  // 컨테이너번호
    acb_adjmTrgtYn.setValue("1");  // 정산대상
    acb_stndPcostYn.setValue("0");  // 표준원가
    rd_transCargoClsCd.setValue("");

    // scwin.udcOnCompleted();


}

//-------------------------------------------------------------------------
// 날짜 UDC 기본값
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function() {
    scwin.f_SetDefaultData();
    ica_qryConKnd1.setInitDate(scwin.strStartDate, scwin.strCurrDate);
    ed_blNm.hide();
    ed_cntrNm.hide();

    ed_pchsClntNo.setValue(scwin.strcopCoClntNo);	
    ed_pchsClntNm.setValue(scwin.strcopCoClntNm);	
    ed_pchsDeptCd.setValue(scwin.strlobranCd);
    ed_pchsDeptNm.setValue(scwin.strlobranNm);

    if(scwin.selPchLodeptCd != "") {
        scwin.f_executeFromLinked();
    }
}



scwin.f_executeFromLinked = function() {
    ed_pchsDeptCd.setValue(scwin.selPchLodeptCd);
    acb_gubun1.setValue("POST_DT");
    let first = scwin.qryConDt + "01";
    ica_qryConKnd1.setInitDate(first,scwin.qryConLastDt)
    // ica_rsltsDtSt.setValue(scwin.qryConDt + "01");
    // ica_rsltsDtEnd.setValue(scwin.qryConLastDt);
    if(scwin.acctCd != ""){
        ed_acctCd.setValue(scwin.acctCd);
        ed_acctNm.setValue(scwin.acctNm);
    }

    scwin.btn_retrieve_onClick();


}

//-------------------------------------------------------------------------
// 계정별 확정/미확정 호출시 조회
//-------------------------------------------------------------------------
scwin.f_WholeRetrieve = function(dma_parent) {
    ed_pchsDeptCd.setValue(dma_parent.get("pchsDeptCd"))
    scwin.udc_pchsDept_onblurCode();
    if(dma_parent.get("dcsnClsCd") == "DCSN"){		
        acb_gubun1.setValue("POST_DT");
    } else if(dma_parent.get("dcsnClsCd") == "NODCSN"){
        acb_gubun1.setValue("RSLTS_DT");
        acb_dcsnClsCd.setValue("3");
        cbx_downClsCd.setValue("T");			
    } else if(dma_parent.get("dcsnClsCd") == "3"){
        acb_gubun1.setValue("RSLTS_DT");
        acb_dcsnClsCd.setValue("3");		
    } else if(dma_parent.get("dcsnClsCd") == "2"){
        acb_gubun1.getValue("RSLTS_DT");
        acb_dcsnClsCd.getValue("2");		
        cbx_downClsCd.setValue("T");
    }		

    acb_gubun2.setValue("COMM_CD");
    ica_rsltsDtSt.setValue(dma_parent.get("rsltsDtSt"));
    ica_rsltsDtEnd.setValue(dma_parent.get("rsltsDtEnd"));

    ed_acctCd.setValue(dma_parent.get("acctCd"));
    scwin.udc_acct_onblurCode();	
    acb_retStd.setValue(dma_parent.get("retStd"));

    scwin.btn_retrieve_onClick();

}






//-------------------------------------------------------------------------
// 거래처별통합매입 조회 / f_RetrieveCustomerEachUnityPurchase
//-------------------------------------------------------------------------
scwin.btn_retrieve_onClick = async function() {
    // 검색조건 필수 입력 체크, 동일 날짜 포함 여부 체크
    if (! await $c.gus.cfValidate([ed_pchsDeptCd])) {
        return;
    }

    // 오더일자/오더번호 구분
    if (acb_gubun1.getValue() == "RSLTS_DT" || acb_gubun1.getValue() == "ODR_DT" || acb_gubun1.getValue() == "INTEND_DT" || acb_gubun1.getValue() == "POST_DT") {
        if (! await $c.gus.cfValidate([ica_rsltsDtSt, ica_rsltsDtEnd])) {
            return;
        }

        if (! await $c.gus.cfIsAfterDate(ica_rsltsDtSt.getValue(), ica_rsltsDtEnd.getValue())) {
            await $c.win.alert("조회 시작일자는 종료일자 보다 이전 날짜 이어야 합니다.");
            ica_rsltsDtSt.focus();
            return;
        }


        // if (!$c.gus.cfValidate([ed_odrNo])) {
        //     return;
        // }		
    }

    // 사업자기준
    if (cbx_crnYn.getValue() == "1") {
        dma_queryConditionDTO.set("crnYn", "Y");
    } else {
        dma_queryConditionDTO.set("crnYn" , "N");
    }

    // 이전/이후
    if (cbx_upClsCd.getValue() == "1") {
        dma_queryConditionDTO.set("upDownClsCd", "UP");
    } else if(cbx_downClsCd.getValue() == "1") {
        dma_queryConditionDTO.set("upDownClsCd", "DOWN");
    } else {
        dma_queryConditionDTO.set("upDownClsCd",  "NULL");
    }

    // BL 번호와 오더번호 구분
    if(acb_gubun1.getValue() == "BL") {
        dma_queryConditionDTO.set("odrNo", ed_blNo.getValue());

    } else if(acb_gubun1.getValue() == "ODR_NO") {
        dma_queryConditionDTO.set("odrNo", ed_odrNo.getValue());
    }

    dma_queryConditionDTO.set("pchsDeptCd", ed_pchsDeptCd.getValue());
    dma_queryConditionDTO.set("gubun1", acb_gubun1.getValue());
    dma_queryConditionDTO.set("rsltsDtSt", ica_rsltsDtSt.getValue());
    dma_queryConditionDTO.set("rsltsDtEnd", ica_rsltsDtEnd.getValue());
    dma_queryConditionDTO.set("gubun2", acb_gubun2.getValue());
    dma_queryConditionDTO.set("commCd", ed_commCd.getValue());
    dma_queryConditionDTO.set("cntrNo", ed_cntrNo.getValue());
    dma_queryConditionDTO.set("pchsClntNo", ed_pchsClntNo.getValue());
    dma_queryConditionDTO.set("copCoClntNo", ed_copCoClntNo.getValue());
    dma_queryConditionDTO.set("bizDomCd", acb_bizDomCd.getValue());
    dma_queryConditionDTO.set("wrkPlCd", ed_wrkPlCd.getValue());
    dma_queryConditionDTO.set("vssl", ed_vsslCd.getValue());
    dma_queryConditionDTO.set("portcnt", ed_portcnt.getValue());
    dma_queryConditionDTO.set("odrKndClsCd", acb_odrKndCd.getValue());
    dma_queryConditionDTO.set("selpchItemCd", acb_selpchItemCd.getValue());
    dma_queryConditionDTO.set("adjmTrgtYn", acb_adjmTrgtYn.getValue());
    dma_queryConditionDTO.set("stndPcostYn", acb_stndPcostYn.getValue());
    dma_queryConditionDTO.set("dcsnClsCd", acb_dcsnClsCd.getValue());
    dma_queryConditionDTO.set("cargoClsCd", rd_transCargoClsCd.getValue());
    dma_queryConditionDTO.set("clntCls", acb_clntCls.getValue());
    dma_queryConditionDTO.set("pchsCertiNo", ed_pchsCertiNo.getValue());
    dma_queryConditionDTO.set("magamStd", acb_magamStd.getValue());
    dma_queryConditionDTO.set("acctCd", ed_acctCd.getValue());
    dma_queryConditionDTO.set("admitPic", ed_admitPic.getValue());
    dma_queryConditionDTO.set("wageRetroactYn", acb_wageRetroactYn.getValue());
    dma_queryConditionDTO.set("cvsslMgntNo", ed_cvsslMgntNo.getValue());
    dma_queryConditionDTO.set("bilgClntNo", ed_bilgClntNo.getValue());
    dma_queryConditionDTO.set("regId", ed_regId.getValue());
    dma_queryConditionDTO.set("modId", ed_modId.getValue());
    dma_queryConditionDTO.set("reqClntNo", ed_reqClntNo.getValue());           //20170530요청처추가

    // 마감년월
    dma_queryConditionDTO.set("closeYm", acb_retStd.getValue());

    if (acb_retStd.getValue() == "") {
        dma_queryConditionDTO.set("retStd", "0");
    } else {
        dma_queryConditionDTO.set("retStd", "1");
    }

    $c.sbm.execute(sbm_queryConditionDTO);

}




//-------------------------------------------------------------------------
// 거래처별통합매입 조회 성공시
//-------------------------------------------------------------------------
scwin.ds_customerEachUnityPurchaseList_ondataload = function (e) {
    let rowCnt = ds_customerEachUnityPurchaseList.getTotalRow();

    spa_totalRowMst.setValue(rowCnt);

    if(rowCnt == 0) {
        ds_orderEachUnityPurchaseList.removeAll();
        $c.win.alert(MSG_CM_ERR_003)
    } else {
        scwin.f_RetrieveOrderEachUnityPurchase(0);
    }
};


//-------------------------------------------------------------------------
// 오더별 통합매입 조회
//-------------------------------------------------------------------------
scwin.f_RetrieveOrderEachUnityPurchase = function(row) {		

    dma_queryConditionDTO.set("pchsClntNoDtl", ds_customerEachUnityPurchaseList.getCellData(row, "pchsClntNo"));
    dma_queryConditionDTO.set("selpchItemCdDtl", ds_customerEachUnityPurchaseList.getCellData(row, "selpchItemCd"));

    // 오더별 매입현황 전체
    if (cbx_totalYn.getValue() == "1") {
        dma_queryConditionDTO.set("totalYn" , "B");
        dma_queryConditionDTO.set("pchsClntNoDtl",  ed_pchsClntNo.getValue());
    } else {
        dma_queryConditionDTO.set("totalYn", "A");
    }

    $c.sbm.execute(sbm_queryConditionDTODtl);
}

//-------------------------------------------------------------------------
// 오더별 통합매입 조회 완료시
//-------------------------------------------------------------------------
scwin.queryConditionDTODtl_submitDone = function (e) {
    let rowCnt = ds_orderEachUnityPurchaseList.getTotalRow()
    spa_totalRowsDtl.setValue(rowCnt);

    // ds_orderEachUnityPurchaseList.setCellData(0,"dcsnClsNm", "미확인");

    for(i = 0; i < rowCnt; i++) {
        if(ds_orderEachUnityPurchaseList.getCellData(i, "dcsnClsNm") != "미확인") {
            gr_orderEachUnityPurchaseList.setCellReadOnly(i, "chk", true);
            gr_orderEachUnityPurchaseList.setCellReadOnly(i, "reqClntNm", true);
            gr_orderEachUnityPurchaseList.setCellReadOnly(i, "pchsClntNm", true);
            gr_orderEachUnityPurchaseList.setCellReadOnly(i, "vehclNo", true);
            gr_orderEachUnityPurchaseList.setCellReadOnly(i, "vat", true);
        }
    }
};


//-------------------------------------------------------------------------
// 대문자 변환
//-------------------------------------------------------------------------
scwin.onkeyup = function (e) {
    this.setValue(e.target.value.toUpperCase());
};


//-------------------------------------------------------------------------
// 오더별 매입현황 그리드 더블 클릭
//-------------------------------------------------------------------------
scwin.gr_order_DblClick = function (rowIndex, columnIndex, columnId) {
    // let colId = ds_orderEachUnityPurchaseList.getColumnID(columnIndex)
    if(rowIndex >= 0){
        if(columnId == "cntrNo" && ds_orderEachUnityPurchaseList.getCellData(rowIndex, "cntrNo") != ""){ 
            scwin.f_cntrNoDetail(ds_orderEachUnityPurchaseList.getCellData(rowIndex, "cntrNo"));
        } else if (columnId == "odrNo" && ds_orderEachUnityPurchaseList.getCellData(rowIndex, "odrNo") != ""){
            scwin.f_orderDetail(ds_orderEachUnityPurchaseList.getCellData(rowIndex, "odrNo"));
        } else if (columnId == "selpchItemNm" && ds_orderEachUnityPurchaseList.getCellData(rowIndex, "selpchItemNm") != ""){
            scwin.f_sellItemDetail(ds_orderEachUnityPurchaseList.getCellData(rowIndex, "odrNo"));
        }		
    }
};


//-------------------------------------------------------------------------
// GRID에서 선택된 cntrNo 세부정보 확인 : 해당 cntrNo 페이지로 이동
//-------------------------------------------------------------------------
scwin.f_cntrNoDetail = function(cntrNo){

    let opt = {
        id: "taxPop", 
        type: "",
        menuName: "컨테이너 화물추적",
        width:  1100,                   
        height: 650
    };

    //팝업 화면에 데이터 보내는 방법 1. json형태로 팝업화면에서 getParameter로 받기
    let args = {
        cntrNo: cntrNo			// 화면에서의 ??? Code Element의	Value
    };

    //상세화면 호출
    $c.win.openMenu("컨테이너 화물추적", "/ui/ds/as/cstmrsrvc/coafmgnt/as_102_01_02b.xml" , "as_102_01_02b.xml", args, opt);
}			

//-------------------------------------------------------------------------
// GRID에서 선택된 오더 세부정보 확인 : 해당 오더유형별 페이지로 이동
//-------------------------------------------------------------------------
scwin.f_orderDetail = function(arg){

    let strOrderDetailUrl = "";
    let strOrderDetailTitle = "";

    let args = {};
    let url = "";
    let opt = {};

    if(arg.substring(1,2) == "B"){
        // 오더 종류가 벌크오더인 경우 - 화물구분(B : 벌크)
        url   = "/ui/ds/sd/odrmgnt/odrreg/sd_402_01_02t.xml";
        opt.pgmId = "sd_402_01_02t.xml"
        opt.menuName = "벌크오더";
    }else if(arg.substring(1,2) == "C"){
        // 오더 종류가 컨테이너 오더인 경우 - 화물구분 (C : 컨테이너)
        url = "/ui/ds/sd/odrmgnt/odrreg/sd_402_01_11t.xml";
        opt.pgmId = "sd_402_01_11t.xml"
        opt.menuName = "컨테이너오더";
    }else if(arg.substring(1,2) == "Z"){
        url = "/ui/ds/fs/adjm/fs_101_01_03b.xml";
        opt.pgmId = "fs_101_01_03b.xml"
        opt.menuName = "기타원가생성";
    }	

    let v_odrNo = arg;
    let v_flag  = "DETAIL";  	


    if(arg.substring(1,2) == "Z"){
        args.odrNo = v_odrNo;
        args.flag = v_flag;
    } else {
        args.odrNo = v_odrNo;
        args.type = "retrieve";
    }

    //상세화면 호출
    $c.win.openMenu(opt.menuName, url, opt.pgmId, args, opt)
}	


//-------------------------------------------------------------------------
// GRID에서 선택된 오더 세부정보 확인 : 해당 오더유형별 페이지로 이동
//-------------------------------------------------------------------------
scwin.f_sellItemDetail = function(arg){
    // let opt = {};
    // let args = {};
    let url = "/ui/ds/sd/odrmgnt/odrreg/sd_402_01_26b.xml";
    // opt.menuName = "통합매출/입관리";
    // opt.pgmId = "sd_402_01_26b.xml"

    // args.v_odrNo = arg;
    // args.type = "retrieve";

    let opt = {
        id: "taxPop", 
        type: "",
        menuName: "컨테이너 화물추적",
        width:  1100,                   
        height: 650
    };

    //팝업 화면에 데이터 보내는 방법 1. json형태로 팝업화면에서 getParameter로 받기
    let args = {
        v_odrNo: arg,
        type : "retrieve"
    };



    $c.win.openMenu("컨테이너화물추적", url, "sd_402_01_26b.xml", args, opt)
}


//-------------------------------------------------------------------------
// 체크박스 처리(사업자기준) / f_crnYn
//-------------------------------------------------------------------------
scwin.cbx_crnYn_Change = function (info) {
    if(cbx_crnYn.getValue() == "1") {
        if($c.gus.cfIsNull(ed_pchsClntNo.getValue())) {
            $c.win.alert("매입거래처를 입력하십시오");
            cbx_crnYn.setValue("0");
            ed_pchsCertiNo.focus();
            return;
        }    
    }
};


//-------------------------------------------------------------------------
// 체크박스 처리(이전)
//-------------------------------------------------------------------------
scwin.cbx_downClsCd_Change = function (info) {
    if(cbx_downClsCd.getValue() == "1") {
        if ($c.gus.cfIsNull(acb_dcsnClsCd.getValue())) {
            $c.win.alert("확정구분을 선택하십시오.");
            cbx_downClsCd.setValue("0");
            acb_dcsnClsCd.focus();
            return;
        }
        cbx_upClsCd.setValue("0");
    }
};


//-------------------------------------------------------------------------
// 체크박스 처리(이후)
//-------------------------------------------------------------------------
scwin.cbx_upClsCd_Change = function (info) {
	if(cbx_upClsCd.getValue() == "1") {
    	if ($c.gus.cfIsNull(acb_dcsnClsCd.getValue())) {
			$c.win.alert("확정구분을 선택하십시오.");
			cbx_upClsCd.setValue("0");
    		acb_dcsnClsCd.focus();
			return;
		}
		cbx_downClsCd.setValue("0");
    }
};

//-------------------------------------------------------------------------
// UDC 공통 팝업 (매입부서)
//-------------------------------------------------------------------------
scwin.udc_pchsDept_onClick = async function (e) {

    udc_pchsDept.cfCommonPopUp(scwin.udc_pchsDept_callBackFunc
    , ed_pchsDeptCd.getValue()
    ,ed_pchsDeptNm.getValue()
    ,"T"
    ,null
    ,null
    ,null
    ,null
    ,null
    ,null
    ,null
    ,null
    ,null
    ,null
    ,null
    ,null
    ,null);
};

scwin.udc_pchsDept_onblurCode = async function (e) {
    if(ed_pchsDeptCd.getValue() != "") {
        udc_pchsDept.cfCommonPopUp(scwin.udc_pchsDept_callBackFunc, ed_pchsDeptCd.getValue() ,"","T",null,null,null,null,null,null,null,null,null,null,null,null,null);
    }else {
        return;
    }
};

scwin.udc_pchsDept_onChangeName = async function (info) {
    if(ed_pchsDeptNm.getValue() != "") {
        udc_pchsDept.cfCommonPopUp(scwin.udc_pchsDept_callBackFunc, "",ed_pchsDeptNm.getValue(),"T",null,null,null,null,null,null,null,null,null,null,null,null,null);
    } else {
        return;
    }
};

//-------------------------------------------------------------------------
// UDC 공통 팝업 콜백(매입부서)
//-------------------------------------------------------------------------
scwin.udc_pchsDept_callBackFunc = function(ret) {
        $c.gus.cfSetReturnValue(ret, ed_pchsDeptCd, ed_pchsDeptNm)
