//-------------------------------------------------------------------------
// 체크복사 / f_changeSellInfoWholeChecked
//-------------------------------------------------------------------------
scwin.btn_copy2_onClick = function (e) {
    let stPos = ds_orderEachUnityPurchaseList.getRowPosition();
    let pchsClntNo   = ds_orderEachUnityPurchaseList.getCellData(stPos, "pchsClntNo");
    let pchsClntNm   = ds_orderEachUnityPurchaseList.getCellData(stPos, "pchsClntNm");


    for(i = stPos; i < ds_orderEachUnityPurchaseList.getTotalRow(); i++){
        if(ds_orderEachUnityPurchaseList.getCellData(i,"chk") == "T"){
            //확정구분코드
            if(ds_orderEachUnityPurchaseList.getCellData(i, "dcsnClsCd") != "1"){ 
                $c.win.alert("미확인 내역만 수정이 가능합니다.", []); //@은(는) 필수 입력 항목입니다
                return false;
            }   

            if ( ds_orderEachUnityPurchaseList.getCellData(i, "dcsnClsCd") == "1"  ){
                    ds_orderEachUnityPurchaseList.setCellData(i,"chk", "T");
            }

            if (gr_orderEachUnityPurchaseList.getFocusedColumnID()== 'pchsClntNo'|| gr_orderEachUnityPurchaseList.getFocusedColumnID()== 'pchsClntNm') {
                ds_orderEachUnityPurchaseList.setCellData(i, "pchsClntNo", pchsClntNo);
                ds_orderEachUnityPurchaseList.setCellData(i, "pchsClntNm",pchsClntNm);
            }
        }
    }
    return true;
};

//-------------------------------------------------------------------------
// 일괄복사 / f_changeSellInfoWhole
//-------------------------------------------------------------------------
scwin.btn_copy_onClick = function (e) {
    let  stPos = gr_orderEachUnityPurchaseList.getFocusedRowIndex();

    if(stPos == -1) {
        return;
    }

    let  pchsClntNo   = ds_orderEachUnityPurchaseList.getCellData(stPos, "pchsClntNo");
    let  pchsClntNm   = ds_orderEachUnityPurchaseList.getCellData(stPos, "pchsClntNm");


    for(i = stPos; i < ds_orderEachUnityPurchaseList.getTotalRow(); i++){
        //확정구분코드
        if(ds_orderEachUnityPurchaseList.getCellData(i, "dcsnClsCd") != "1"){ 

            $c.win.alert("미확인 내역만 수정이 가능합니다.", []); //@은(는) 필수 입력 항목입니다
            return false;
        }   

        if ( ds_orderEachUnityPurchaseList.getCellData(i, "dcsnClsCd") == "1"  ){
                ds_orderEachUnityPurchaseList.setCellData(i,"chk", "T");
        }

        if (gr_orderEachUnityPurchaseList.getFocusedColumnID()== "pchsClntNo"|| gr_orderEachUnityPurchaseList.getFocusedColumnID()== "pchsClntNm") {
            ds_orderEachUnityPurchaseList.setCellData(i, "pchsClntNo", pchsClntNo);
            ds_orderEachUnityPurchaseList.setCellData(i, "pchsClntNm", pchsClntNm);
        }
    }
    return true;
};


//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.btn_saveSell_onClick = async function (e) {

    if(await $c.win.confirm(MSG_CM_CRM_001)){ //저장하시겠습니까?
        // modifiedIndex가 오더번호를 return함
        if(ds_orderEachUnityPurchaseList.getModifiedIndex().length != 0){    
            let checkedCnt = 0;
            for(let i=0; i < ds_orderEachUnityPurchaseList.getTotalRow(); i++){
                if(ds_orderEachUnityPurchaseList.getCellData(i, "chk") == "T"){
                    checkedCnt++;
                    break;
                }
            }

            // 차량번호 공백인 row는 입력 요청
            for (i=0; i < ds_orderEachUnityPurchaseList.getTotalRow(); i++) {
                //alert();
                if(ds_orderEachUnityPurchaseList.getCellData(i, "chk") == "T" 
                    && (ds_orderEachUnityPurchaseList.getCellData(i, "odrNo").substring(1,3) == DsConstants.ODR_KND_CD_GNRL_BILG_ODR)
                    && (ds_orderEachUnityPurchaseList.getCellData(i, "selpchItemCd") == "0010" || ds_orderEachUnityPurchaseList.getCellData(i, "selpchItemCd") == "0131")) {

                    if (ds_orderEachUnityPurchaseList.getCellData(i, "vehclNo") == "") {
                        $c.win.alert(i + "번째 데이타의 차량번호를 입력하십시오.");
                        return;
                    }
                }
            }            

            // 체크값 확인
            if(checkedCnt == 0){
                $c.win.alert("체크된 데이터가 없습니다.");
                return false;
            }    
            if($c.gus.cfValidate([gr_orderEachUnityPurchaseList])){
                $c.sbm.execute(sbm_savePchsInfo);
            }
        }else{
           $c.win.alert($c.data.getMessage(MSG_CM_ERR_001, "통합매입일괄수정")); //@은(는) 변경된 사항이 없습니다.
        }  
    }



};


