    scwin.olddata = value;

};

//-------------------------------------------------------------------------
// 오더별 매입 현황 그리드 편집 후 killfocus
//-------------------------------------------------------------------------
scwin.gr_orderEachUnityPurchaseList_onafteredit = function (rowIndex, columnIndex, value) {
    let colid = gr_orderEachUnityPurchaseList.getColumnID(columnIndex);

    if(value == scwin.olddata && value != "") {
        return;
    }

    if(value == "" && colid == "pchsClntNm") {
        ds_orderEachUnityPurchaseList.setCellData(rowIndex, "pchsClntNm", "")
        ds_orderEachUnityPurchaseList.setCellData(rowIndex, "pchsClntNo", "")
        return;
        // return;
    }
    if(value == "" && colid == "reqClntNm") {
        ds_orderEachUnityPurchaseList.setCellData(rowIndex, "reqClntNo", "")
        ds_orderEachUnityPurchaseList.setCellData(rowIndex, "reqClntNm", "")
        return;
        // return;
    }



    switch(colid) {
        case "reqClntNm" :
            scwin.f_openComPopUpGrid(1, rowIndex, ds_orderEachUnityPurchaseList.getCellData(rowIndex, "reqClntNo"),ds_orderEachUnityPurchaseList.getCellData(rowIndex, "reqClntNm"), "F", "F", "ontextimageclick", value)
        break


        case "pchsClntNm" : 
            if(ds_orderEachUnityPurchaseList.getCellData(rowIndex, "dcsnClsCd") != "1") {
                return;
            }
            scwin.f_openComPopUpGrid(2, rowIndex, ds_orderEachUnityPurchaseList.getCellData(rowIndex, "pchsClntNo"),ds_orderEachUnityPurchaseList.getCellData(rowIndex, "pchsClntNm"), "F", "T", 'onafteredit', value)
        break

        default :
        break
    }

};

//-------------------------------------------------------------------------
// 매출그리드 요청거래처 팝업
//-------------------------------------------------------------------------
scwin.grid_commonPopup = function(rowIndex, columnIndex) {
    let value = ds_orderEachUnityPurchaseList.getCellData(rowIndex, columnIndex);

    switch(gr_orderEachUnityPurchaseList.getColumnID(columnIndex)) {
        case "reqClntNm" :
            scwin.f_openComPopUpGrid(1, rowIndex, ds_orderEachUnityPurchaseList.getCellData(rowIndex, "reqClntNo"),ds_orderEachUnityPurchaseList.getCellData(rowIndex, "reqClntNm"), "F", "F", "ontextimageclick", value)
        break

        case "pchsClntNm" : 
            if(ds_orderEachUnityPurchaseList.getCellData(rowIndex, "dcsnClsCd") != "1") {
                $c.win.alert("확정구분이 미확인 상태만 수정할 수 있습니다.");
                return false;
            }
            scwin.f_openComPopUpGrid(2, rowIndex, ds_orderEachUnityPurchaseList.getCellData(rowIndex, "pchsClntNo"),ds_orderEachUnityPurchaseList.getCellData(rowIndex, "pchsClntNm"), "F", "F", "ontextimageclick", value)
        break

        case "vehclNo" : 
            if(ds_orderEachUnityPurchaseList.getCellData(rowIndex, "dcsnClsCd") != "1") {
                $c.win.alert("확정구분이 미확인 상태만 수정할 수 있습니다.");
                return false;
            }

            if(ds_orderEachUnityPurchaseList.getCellData(rowIndex, "pchsClntNm") == "") {
                $c.win.alert("매입거래처명을 입력하셔야 수정할 수 있습니다.")
                return false;
            }

            scwin.f_openComPopUpGrid(3, rowIndex, "",ds_orderEachUnityPurchaseList.getCellData(rowIndex, "vehclNo"), "F", "F", "ontextimageclick", value)
        break
        default :
        break
    }
};

//-------------------------------------------------------------------------
// 매출그리드 팝업
//-------------------------------------------------------------------------
scwin.f_openComPopUpGrid = function(disGubun, row, pCode, pName, pClose, pAllSearch) {
    let evNm = arguments[6] || "";

    if (evNm && $c.win.getEventList(gr_orderEachUnityPurchaseList, evNm)) {
        scwin.eventCnt++;
    }


    $p.setTimeout(function () {
        scwin.eventCnt = 0;
    }, { delay: 1500 });

    // if(evNm == "onafteredit" && arguments[7] == "") {
    //     return;
    // }

    let pWhere = "";
    switch(disGubun) {
        case 1 :
            if (scwin.eventCnt == 1) {

                ds_orderEachUnityPurchaseList.setCellData(row, "reqClntNo", "");
                ds_orderEachUnityPurchaseList.setCellData(row, "reqClntNm", "");

                udc_comCode_Grid.setSelectId("retrieveClntInfo");
                udc_comCode_Grid.cfCommonPopUp(
                scwin.udc_comCode_Grid1_CallBackFunc
                , pCode
                , pName
                , pClose
                , null
                , null
                , null
                , null
                , pWhere
                , null
                , null
                , null
                , null
                , null
                , pAllSearch
                , null);
            }
        break

        case 2 : 
            if (scwin.eventCnt == 1) {
                ds_orderEachUnityPurchaseList.setCellData(row, "pchsClntNo", "");
                ds_orderEachUnityPurchaseList.setCellData(row, "pchsClntNm", "");

                udc_comCode_Grid.setSelectId("retrieveClntInfo");
                udc_comCode_Grid.cfCommonPopUp(
                scwin.udc_comCode_Grid2_CallBackFunc
                , pCode
                , pName
                , pClose
                , null
                , null
                , null
                , null
                , pWhere
                , null
                , null
                , null
                , null
                , null
                , pAllSearch
                , null);
            }
        break

        case 3 : 
            if (scwin.eventCnt == 1) {

                ds_orderEachUnityPurchaseList.setCellData(row, "vehclNo", "");
                udc_comCode_Grid.setSelectId("retrieveVehclList");
                udc_comCode_Grid.cfCommonPopUp(
                scwin.udc_comCode_Grid3_CallBackFunc
                , pCode
                , pName
                , pClose
                , null
                , null
                , null
                , null
                , pWhere
                , null
                , null
                , null
                , null
                , null
                , pAllSearch
                , null);
            }
        default:
        break
    }
};

